/**
 * @fileoverview Select (native) constants.
 * @module module/Select/constants
 */

import { TRANSITION_COLORS } from '../shared/styleFragments.js';
import { defineParts } from '../shared/definePart.js';

export const CLS = Object.freeze({
    ROOT:        'select',
    WRAPPER:     'select-wrapper',
    FIELD:       'select-field',
    LABEL:       'select-label',
    DESCRIPTION: 'select-description',
    CHEVRON:     'select-chevron',
    DISABLED:    'is-disabled',
    INVALID:     'is-invalid',
});

export const DEFAULTS = Object.freeze({});

export const PART = defineParts('Select', {
    ROOT        : { class: 'select-root', aliases: ['root', 'select'] },
    WRAPPER     : { class: 'select-wrapper', aliases: ['wrapper'] },
    FIELD       : { class: 'select-field', aliases: ['field'] },
    LABEL       : { class: 'select-label', aliases: ['label'] },
    DESCRIPTION : { class: 'select-description', aliases: ['description', 'desc'] },
    CHEVRON     : { class: 'select-chevron', aliases: ['chevron'] },
});

PART.ROOT.jit     = 'flex flex-col gap-[var(--sl-gap)] {is-disabled}:opacity-50';
PART.LABEL.jit    = 'text-[var(--sl-label-size)] font-medium fg-[var(--sl-label-text)]';
PART.DESCRIPTION.jit = 'text-[var(--sl-desc-size)] fg-[var(--sl-desc-text)]';
PART.WRAPPER.jit  = 'relative';
PART.FIELD.jit    = `w-full appearance-none bg-[var(--sl-bg)] fg-[var(--sl-text)] text-[var(--sl-font-size)] rounded-[var(--sl-radius)] px-[var(--sl-px)] py-[var(--sl-py)] pr-[var(--sl-pr)] [border:1px_solid_var(--sl-border)] ${TRANSITION_COLORS} focus:outline-none focus:[border-color:var(--sl-focus-border)] {is-invalid}:[border-color:var(--sl-error-border)] {is-disabled}:cursor-not-allowed`;
PART.CHEVRON.jit  = 'pointer-events-none absolute right-[var(--sl-chevron-right)] top-1/2 -translate-y-1/2 fg-[var(--sl-chevron-text)]';